import React, { Component } from 'react';
import aboutImg from '../assets/crop.jpg';

class About extends Component {
    render() {
        return (
            <div className="content">
                <div className="about-style">
                    <h1>About</h1>
                    <div className="about-holder">
                        <img src={aboutImg} alt="about-img"/>
                        <div className="about-text">
                            <ul> 
                                <li>Howdy! My name is Helena.</li>
                                <li>I'm a 3rd Year CS Major @ Georgia Tech.</li>
                                <li>I'm the VP for the Women @ College of Computing.</li>
                                <li>I'm a member of HackGT's Operations Team.</li>
                            </ul>

                        </div>
                    </div>
                </div>
            </div>
        )
    }
}

export default About;
